// 'id1'というidを持つ親要素の全ての子要素に'class1'というクラスを追加します。
let parent = document.getElementById('id1');
Array.from(parent.children).forEach((child) => {
  child.classList.add('class1');
});
// このコードを実行すると、'id1'というidを持つ親要素の全ての子要素に'class1'というクラスが追加されます。

// 全ての'class1'というクラスを持つ要素を抽出します。
let elements = document.getElementsByClassName('class1');
console.log(elements);
// このコードを実行すると、コンソールに全ての'class1'というクラスを持つ要素のリストが表示されます。

// 'id1'というidを持つ親要素の全ての子要素から'class1'というクラスを削除します。
let parent = document.getElementById('id1');
Array.from(parent.children).forEach((child) => {
  child.classList.remove('class1');
});
// このコードを実行すると、'id1'というidを持つ親要素の全ての子要素から'class1'というクラスが削除されます。

// 'id1'というidを持つ要素の'class1'というクラスを'class2'に切り替えます。
let element = document.getElementById('id1');
element.classList.replace('class1', 'class2');
// このコードを実行すると、'id1'というidを持つ要素の'class1'というクラスが'class2'に切り替えられます。

// ページ内の'class1'というクラスを持つすべての要素のクラスを'class2'に切り替えます。
let elements = document.getElementsByClassName('class1');
Array.from(elements).forEach((element) => {
  element.classList.replace('class1', 'class2');
});
// このコードを実行すると、ページ内の'class1'というクラスを持つすべての要素のクラスが'class2'に切り替えられます。

// ページ内の'class1'というクラスを持つ要素の数を取得します。
let elements = document.getElementsByClassName('class1');
console.log(elements.length);
// このコードを実行すると、ページ内の'class1'というクラスを持つ要素の数がコンソールに出力されます。

// 親要素'id_parent'から'class1'というクラスを持つ子要素全てのクラスを'class2'に切り替えます。
let parent = document.getElementById('id_parent');
let children = parent.getElementsByClassName('class1');
Array.from(children).forEach((child) => {
  child.classList.replace('class1', 'class2');
});
// このコードを実行すると、親要素'id_parent'から'class1'というクラスを持つ子要素全てのクラスが'class2'に切り替えられます。

// ページ内に'class1'というクラスを持つ要素が存在するかどうかを判定します。
let elements = document.getElementsByClassName('class1');
if (elements.length > 0) {
  console.log('存在します');
} else {
  console.log('存在しません');
}
// このコードを実行すると、ページ内に'class1'というクラスを持つ要素が存在するかどうかがコンソールに出力されます。

// 'id1'というidを持つ要素から'class2'を削除し、'class4'を追加します。
let element = document.getElementById('id1');
element.classList.remove('class2');
element.classList.add('class4');
// このコードを実行すると、'id1'というidを持つ要素から'class2'が削除され、'class4'が追加されます。

// ページ内の'class1'というクラスを持つ全ての要素のクラスを'class2'に切り替えます。
let elements = document.getElementsByClassName('class1');
Array.from(elements).forEach((element) => {
  element.classList.replace('class1', 'class2');
});
// このコードを実行すると、ページ内の'class1'というクラスを持つ全ての要素のクラスが'class2'に切り替えられます。
